import { useSessionStore } from '@/stores/session';
import { ref, computed } from 'vue';

/**
 * Session store — owns the session identity, prompt state, and I/O history.
 *
 * This replaces ~30 scattered refs in the monolith's setup() that all relate
 * to the prompt/response lifecycle.
 */
export const useSessionStore = defineStore('session', () => {
  // ── Identity ───────────────────────────────────────────────────────
  const sessionId = ref(localStorage.getItem('vox_session_id') || 'sess_' + Math.random().toString(36).substr(2, 9));
  localStorage.setItem('vox_session_id', sessionId.value);

  // ── Prompt input ───────────────────────────────────────────────────
  const inputText = ref('');
  const stochasticity = ref(0.3);
  const attachedImage = ref<string | null>(null);
  const attachedImageBase64 = ref<string | null>(null);
  const recordedAudio = ref<Blob | null>(null);
  const recordedAudioBase64 = ref<string | null>(null);
  const recordedAudioDuration = ref(0);
  const isDragging = ref(false);

  // ── Prompt state machine ───────────────────────────────────────────
  const sending = ref(false);
  const promptState = ref<'ready' | 'warming' | 'sending' | 'awaiting' | 'complete' | 'quiet' | 'error'>('warming');
  const promptStateText = ref('Initializing backend session...');

  // ── Latest response ────────────────────────────────────────────────
  const lastResponse = ref('');
  const lastPrompt = ref('');
  const lastPromptSource = ref('user');
  const lastResponseReason = ref('');
  const lastRequestId = ref('');
  const pendingRequestId = ref('');
  const responseTimeMs = ref<number | null>(null);
  const responseHardware = ref<Record<string, any> | null>(null);
  const currentTick = ref(25000);

  // ── History ────────────────────────────────────────────────────────
  interface PromptHistoryEntry {
    id: string;
    source: string;
    phase: string;
    time: string;
    prompt: string;
    response: string;
    reason?: string;
  }
  const promptHistory = ref<PromptHistoryEntry[]>([]);

  // ── Computed ───────────────────────────────────────────────────────
  const promptStateClass = computed(() => promptState.value);
  const promptStateLabel = computed(() => {
    const map: Record<string, string> = {
      ready: 'READY',
      warming: 'WARMING',
      sending: 'SENDING',
      awaiting: 'AWAITING',
      complete: 'COMPLETE',
      quiet: 'QUIET',
      error: 'ERROR',
    };
    return map[promptState.value] || promptState.value.toUpperCase();
  });

  const sendButtonLabel = computed(() =>
    sending.value ? 'Thinking...' : attachedImage.value ? 'Send 🖼️' : 'Send'
  );

  const responseTimeLabel = computed(() => {
    if (responseTimeMs.value == null) return '';
    const ms = responseTimeMs.value;
    if (ms < 1000) return `${ms.toFixed(0)}ms`;
    return `${(ms / 1000).toFixed(2)}s`;
  });

  const responseReasonClass = computed(() => {
    const r = lastResponseReason.value;
    if (r === 'quiet' || r === 'silence') return 'quiet';
    if (r === 'error') return 'error';
    return 'complete';
  });

  // ── Actions ────────────────────────────────────────────────────────
  function clearImage() {
    attachedImage.value = null;
    attachedImageBase64.value = null;
  }

  function clearRecording() {
    recordedAudio.value = null;
    recordedAudioBase64.value = null;
    recordedAudioDuration.value = 0;
  }

  function addToHistory(entry: PromptHistoryEntry) {
    promptHistory.value = [entry, ...promptHistory.value.slice(0, 23)];
  }

  return {
    sessionId,
    inputText,
    stochasticity,
    attachedImage,
    attachedImageBase64,
    recordedAudio,
    recordedAudioBase64,
    recordedAudioDuration,
    isDragging,
    sending,
    promptState,
    promptStateText,
    lastResponse,
    lastPrompt,
    lastPromptSource,
    lastResponseReason,
    lastRequestId,
    pendingRequestId,
    responseTimeMs,
    responseHardware,
    currentTick,
    promptHistory,
    promptStateClass,
    promptStateLabel,
    sendButtonLabel,
    responseTimeLabel,
    responseReasonClass,
    responseReasonLabel,
    clearImage,
    clearRecording,
    addToHistory,
  };
});
