import { defineComponent } from 'vue';

export default defineComponent({
  name: 'ResetSessionButton',
  data() {
    return {
      sessionId: '',
      inputText: '',
      stochasticity: 0.3,
      attachedImage: null,
      attachedImageBase64: null,
      recordedAudio: null,
      recordedAudioBase64: null,
      recordedAudioDuration: 0,
      isDragging: false,
    };
  },
  methods: {
    async resetSession() {
      await this.$nextTick();
      // Clear image and recording
      clearImage();
      clearRecording();

      // Reset prompt state to 'ready' or 'sending'
      this.promptState = 'warming';
      this.lastResponse = '';
      this.lastPrompt = '';
      this.lastPromptSource = 'user';

      // Set response time as 0ms
      this.responseTimeMs = 0;
    },
  },
});

